-- CaseOver database seed v3
-- Academic dataset: response time vs conversion study


CREATE TYPE customer_type_enum AS ENUM ('lead', 'first_time_customer', 'returning_customer', 'vip_customer');
CREATE TYPE platform_enum AS ENUM ('website', 'email', 'instagram', 'whatsapp');
CREATE TYPE contact_reason_enum AS ENUM ('product_question','price_question','stock_availability','shipping_question','order_status','return_or_exchange','warranty_or_issue','customization_request','complaint','other');
CREATE TYPE order_status_enum AS ENUM ('pending','paid','processing','shipped','delivered','cancelled','returned','refunded');
CREATE TYPE agent_role_enum AS ENUM ('ceo', 'employee');
CREATE TYPE sender_enum AS ENUM ('customer', 'agent');
CREATE TYPE product_status_enum AS ENUM ('active', 'out_of_stock', 'discontinued');

CREATE TABLE categories (
    category_id UUID PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    parent_id UUID REFERENCES categories(category_id)
);

CREATE TABLE customers (
    customer_id UUID PRIMARY KEY,
    email VARCHAR(255) NOT NULL,
    name VARCHAR(100) NOT NULL,
    customer_type customer_type_enum NOT NULL,
    created_at TIMESTAMP NOT NULL,
    total_orders INT DEFAULT 0
);

CREATE TABLE agents (
    agent_id UUID PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    role agent_role_enum NOT NULL
);

CREATE TABLE products (
    product_id UUID PRIMARY KEY,
    category_id UUID REFERENCES categories(category_id),
    name VARCHAR(200) NOT NULL,
    price DECIMAL(10,2) NOT NULL,
    sku VARCHAR(50) NOT NULL,
    stock INT NOT NULL,
    status product_status_enum NOT NULL DEFAULT 'active'
);

CREATE TABLE orders (
    order_id UUID PRIMARY KEY,
    customer_id UUID REFERENCES customers(customer_id),
    product_id UUID REFERENCES products(product_id),
    amount DECIMAL(10,2) NOT NULL,
    status order_status_enum NOT NULL,
    ordered_at TIMESTAMP NOT NULL
);

CREATE TABLE contacts (
    contact_id UUID PRIMARY KEY,
    customer_id UUID REFERENCES customers(customer_id),
    product_id UUID REFERENCES products(product_id),
    order_id UUID REFERENCES orders(order_id),
    agent_id UUID REFERENCES agents(agent_id),
    platform platform_enum NOT NULL,
    contact_reason contact_reason_enum NOT NULL,
    first_message_at TIMESTAMP NOT NULL,
    first_response_at TIMESTAMP NOT NULL,
    response_time_min INT NOT NULL
);

CREATE TABLE messages (
    message_id UUID PRIMARY KEY,
    contact_id UUID REFERENCES contacts(contact_id),
    sender sender_enum NOT NULL,
    content TEXT NOT NULL,
    sent_at TIMESTAMP NOT NULL
);

CREATE TABLE conversions (
    conversion_id UUID PRIMARY KEY,
    contact_id UUID UNIQUE REFERENCES contacts(contact_id),
    order_id UUID REFERENCES orders(order_id),
    converted BOOLEAN NOT NULL,
    conversion_value DECIMAL(10,2),
    window_hours INT NOT NULL DEFAULT 24
);

